import React, { useState, useEffect } from 'react';
import './App.css';

interface Todo {
  id: number;
  text: string;
  completed: boolean;
  category?: '개인' | '회사';
  createdAt?: string;
  completedAt?: string;
}

function App() {
  const [todos, setTodos] = useState<Todo[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [category, setCategory] = useState<'개인' | '회사'>('개인');
  const [filter, setFilter] = useState<'all' | 'active' | 'completed'>('all');

  const API_URL = 'http://localhost:5000/api/todos';

  // Load todos on mount
  useEffect(() => {
    fetchTodos();
  }, []);

  const fetchTodos = async () => {
    try {
      const response = await fetch(API_URL);
      const data = await response.json();
      setTodos(data);
    } catch (error) {
      console.error('Error fetching todos:', error);
    }
  };

  const formatDate = (dateString?: string) => {
    if (!dateString) return '';
    const date = new Date(dateString);
    return `${date.getMonth() + 1}/${date.getDate()} ${date.getHours()}:${String(date.getMinutes()).padStart(2, '0')}`;
  };

  const addTodo = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          text: inputValue,
          category: category 
        }),
      });
      const newTodo = await response.json();
      setTodos([...todos, newTodo]);
      setInputValue('');
    } catch (error) {
      console.error('Error adding todo:', error);
    }
  };

  const toggleTodo = async (id: number) => {
    try {
      const response = await fetch(`${API_URL}/${id}`, {
        method: 'PATCH',
      });
      if (response.ok) {
        const updatedTodo = await response.json();
        setTodos(
          todos.map((todo) =>
            todo.id === id ? updatedTodo : todo
          )
        );
      }
    } catch (error) {
      console.error('Error toggling todo:', error);
    }
  };

  const deleteTodo = async (id: number) => {
    try {
      const response = await fetch(`${API_URL}/${id}`, {
        method: 'DELETE',
      });
      if (response.ok) {
        setTodos(todos.filter((todo) => todo.id !== id));
      }
    } catch (error) {
      console.error('Error deleting todo:', error);
    }
  };

  const filteredTodos = todos.filter((todo) => {
    if (filter === 'active') return !todo.completed;
    if (filter === 'completed') return todo.completed;
    return true;
  });

  return (
    <div className="container">
      <div className="todo-card">
        <h1>TaskFlow</h1>
        <form onSubmit={addTodo} className="input-group">
          <select 
            value={category} 
            onChange={(e) => setCategory(e.target.value as '개인' | '회사')}
            className="category-select"
          >
            <option value="개인">개인</option>
            <option value="회사">회사</option>
          </select>
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            placeholder="할 일을 입력하세요..."
          />
          <button type="submit">추가</button>
        </form>

        <div className="filters">
          <button
            className={filter === 'all' ? 'active' : ''}
            onClick={() => setFilter('all')}
          >
            전체
          </button>
          <button
            className={filter === 'active' ? 'active' : ''}
            onClick={() => setFilter('active')}
          >
            진행 중
          </button>
          <button
            className={filter === 'completed' ? 'active' : ''}
            onClick={() => setFilter('completed')}
          >
            완료됨
          </button>
        </div>

        <ul className="todo-list">
          {filteredTodos.map((todo) => (
            <li key={todo.id} className={`${todo.completed ? 'completed' : ''} ${todo.category === '회사' ? 'work' : 'personal'}`}>
              <div className="todo-item-content" onClick={() => toggleTodo(todo.id)}>
                <span className="checkbox">
                  {todo.completed ? '✓' : ''}
                </span>
                <div className="text-container">
                  <div className="todo-header">
                    <span className="category-badge">{todo.category}</span>
                    <span className="text">{todo.text}</span>
                  </div>
                  <div className="date-info">
                    {todo.createdAt && <span>작성: {formatDate(todo.createdAt)}</span>}
                    {todo.completedAt && <span className="completed-date">완료: {formatDate(todo.completedAt)}</span>}
                  </div>
                </div>
              </div>
              <button className="delete-btn" onClick={(e) => {
                e.stopPropagation();
                deleteTodo(todo.id);
              }}>
                삭제
              </button>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

export default App;
